  6â†’package kotlinx.datetime.internal.format.parser
  7â†’
  8â†’import kotlinx.datetime.internal.*
  9â†’
 10â†’/**
 11â†’ * A parser that expects to receive a string consisting of [length] digits, or, if [length] is `null`,
 12â†’ * a string consisting of any number of digits.
 13â†’ */
 14â†’internal sealed class NumberConsumer<in Receiver>(
 15â†’    /** The number of digits to consume. `null` means that the length is variable. */
 16â†’    open val length: Int?,
 17â†’    /** The human-readable name of the entity being parsed here. */
 18â†’    val whatThisExpects: String
 19â†’) {
 20â†’    /**
 21â†’     * Wholly consumes the substring of [input] between indices [start] (inclusive) and [end] (exclusive).
 22â†’     *
 23â†’     * If [length] is non-null, [end] must be equal to [start] + [length].
 24â†’     * In any case, the substring between [start] and [end] must consist of ASCII digits only.
 25â†’     * [consume] itself does not necessarily check the length of the input string,
 26â†’     * instead expecting to be given a valid one.
 27â†’     *
 28â†’     * Returns `null` on success and a `NumberConsumptionError` on failure.
 29â†’     */
 30â†’    abstract fun consume(storage: Receiver, input: CharSequence, start: Int, end: Int): NumberConsumptionError?
 31â†’}
 32â†’
 33â†’internal interface NumberConsumptionError {
 34â†’    fun errorMessage(): String
 35â†’    object ExpectedInt: NumberConsumptionError {
 36â†’        override fun errorMessage() = "expected an Int value"
 37â†’    }
 38â†’    class TooManyDigits(val maxDigits: Int): NumberConsumptionError {
 39â†’        override fun errorMessage() = "expected at most $maxDigits digits"
 40â†’    }
 41â†’    class TooFewDigits(val minDigits: Int): NumberConsumptionError {
 42â†’        override fun errorMessage() = "expected at least $minDigits digits"
 43â†’    }
 44â†’    class WrongConstant(val expected: String): NumberConsumptionError {
 45â†’        override fun errorMessage() = "expected '$expected'"
 46â†’    }
 47â†’    class Conflicting(val conflicting: Any): NumberConsumptionError {
 48â†’        override fun errorMessage() = "attempted to overwrite the existing value '$conflicting'"
 49â†’    }
 50â†’}
 51â†’
 52â†’/**
 53â†’ * A parser that accepts an [Int] value in range from `0` to [Int.MAX_VALUE].
 54â†’ */
 55â†’internal class UnsignedIntConsumer<in Receiver>(
 56â†’    private val minLength: Int?,
 57â†’    private val maxLength: Int?,
 58â†’    private val setter: AssignableField<Receiver, Int>,
 59â†’    name: String,
 60â†’    private val multiplyByMinus1: Boolean = false,
 61â†’) : NumberConsumer<Receiver>(if (minLength == maxLength) minLength else null, name) {
 62â†’
 63â†’    init {
 64â†’        require(length == null || length in 1..9) { "Invalid length for field $whatThisExpects: $length" }
 65â†’    }
 66â†’
 67â†’    override fun consume(storage: Receiver, input: CharSequence, start: Int, end: Int): NumberConsumptionError? = when {
 68â†’        maxLength != null && end - start > maxLength -> NumberConsumptionError.TooManyDigits(maxLength)
 69â†’        minLength != null && end - start < minLength -> NumberConsumptionError.TooFewDigits(minLength)
 70â†’        else -> when (val result = input.parseAsciiIntOrNull(start = start, end = end)) {
 71â†’            null -> NumberConsumptionError.ExpectedInt
 72â†’            else -> setter.setWithoutReassigning(storage, if (multiplyByMinus1) -result else result)
 73â†’        }
 74â†’    }
 75â†’}
 76â†’
 77â†’internal class ReducedIntConsumer<in Receiver>(
 78â†’    override val length: Int,
 79â†’    private val setter: AssignableField<Receiver, Int>,
 80â†’    name: String,
 81â†’    val base: Int,
 82â†’): NumberConsumer<Receiver>(length, name) {
 83â†’
 84â†’    private val modulo = POWERS_OF_TEN[length]
 85â†’    private val baseMod = base % modulo
 86â†’    private val baseFloor = base - baseMod
 87â†’
 88â†’    init {
 89â†’        require(length in 1..9) { "Invalid length for field $whatThisExpects: $length" }
 90â†’    }
 91â†’
 92â†’    override fun consume(storage: Receiver, input: CharSequence, start: Int, end: Int): NumberConsumptionError? {
 93â†’        val result = input.parseAsciiInt(start = start, end = end)
 94â†’        return setter.setWithoutReassigning(storage, if (result >= baseMod) {
 95â†’            baseFloor + result
 96â†’        } else {
 97â†’            baseFloor + modulo + result
 98â†’        })
 99â†’    }
100â†’}
101â†’
102â†’/**
103â†’ * A parser that consumes exactly the string [expected].
104â†’ */
105â†’internal class ConstantNumberConsumer<in Receiver>(
106â†’    private val expected: String
107â†’) : NumberConsumer<Receiver>(expected.length, "the predefined string $expected") {
108â†’    override fun consume(storage: Receiver, input: CharSequence, start: Int, end: Int): NumberConsumptionError? =
109â†’        if (input.substring(startIndex = start, endIndex = end) == expected) {
110â†’            null
111â†’        } else {
112â†’            NumberConsumptionError.WrongConstant(expected)
113â†’        }
114â†’}
115â†’
116â†’internal class FractionPartConsumer<in Receiver>(
117â†’    private val minLength: Int,
118â†’    private val maxLength: Int,
119â†’    private val setter: AssignableField<Receiver, DecimalFraction>,
120â†’    name: String,
121â†’) : NumberConsumer<Receiver>(if (minLength == maxLength) minLength else null, name) {
122â†’    init {
123â†’        require(minLength in 1..9) {
124â†’            "Invalid minimum length $minLength for field $whatThisExpects: expected 1..9"
125â†’        }
126â†’        require(maxLength in minLength..9) {
127â†’            "Invalid maximum length $maxLength for field $whatThisExpects: expected $minLength..9"
128â†’        }
129â†’    }
130â†’
131â†’    override fun consume(storage: Receiver, input: CharSequence, start: Int, end: Int): NumberConsumptionError? = when {
132â†’        end - start < minLength -> NumberConsumptionError.TooFewDigits(minLength)
133â†’        end - start > maxLength -> NumberConsumptionError.TooManyDigits(maxLength)
134â†’        else -> setter.setWithoutReassigning(
135â†’            storage, DecimalFraction(input.parseAsciiInt(start = start, end = end), end - start)
136â†’        )
137â†’    }
138â†’}
139â†’
140â†’private fun <Object, Type> AssignableField<Object, Type>.setWithoutReassigning(
141â†’    receiver: Object,
142â†’    value: Type,
143â†’): NumberConsumptionError? {
144â†’    val conflictingValue = trySetWithoutReassigning(receiver, value) ?: return null
145â†’    return NumberConsumptionError.Conflicting(conflictingValue)
146â†’}
