148â†’/**
149â†’ * Parses a substring of the receiver string as a positive ASCII integer.
150â†’ *
151â†’ * All characters between [start] (inclusive) and [end] (exclusive) must be ASCII digits,
152â†’ * and the size of the substring must be at most 9, but the function does not check it.
153â†’ */
154â†’private fun CharSequence.parseAsciiInt(start: Int, end: Int): Int {
155â†’    var result = 0
156â†’    for (i in start until end) {
157â†’        val digit = this[i]
158â†’        result = result * 10 + digit.asciiDigitToInt()
159â†’    }
160â†’    return result
161â†’}
162â†’
163â†’/**
164â†’ * Parses a substring of the receiver string as a positive ASCII integer.
165â†’ *
166â†’ * All characters between [start] (inclusive) and [end] (exclusive) must be ASCII digits,
167â†’ * but the function does not check it.
168â†’ *
169â†’ * Returns `null` if the result does not fit into a positive [Int].
170â†’ */
171â†’private fun CharSequence.parseAsciiIntOrNull(start: Int, end: Int): Int? {
172â†’    var result = 0
173â†’    for (i in start until end) {
174â†’        val digit = this[i]
175â†’        result = result * 10 + digit.asciiDigitToInt()
176â†’        if (result < 0) return null
177â†’    }
178â†’    return result
179â†’}
