149â†’    @Test
150â†’    fun unitsUntil() {
151â†’        val data = listOf(
152â†’                Pair(Pair("2012-06-30", "2012-06-30"), Pair(DateTimeUnit.DAY, 0)),
153â†’                Pair(Pair("2012-06-30", "2012-06-30"), Pair(DateTimeUnit.WEEK, 0)),
154â†’                Pair(Pair("2012-06-30", "2012-06-30"), Pair(DateTimeUnit.MONTH, 0)),
155â†’                Pair(Pair("2012-06-30", "2012-06-30"), Pair(DateTimeUnit.YEAR, 0)),
156â†’                Pair(Pair("2012-06-30", "2012-07-01"), Pair(DateTimeUnit.DAY, 1)),
157â†’                Pair(Pair("2012-06-30", "2012-07-01"), Pair(DateTimeUnit.WEEK, 0)),
158â†’                Pair(Pair("2012-06-30", "2012-07-01"), Pair(DateTimeUnit.MONTH, 0)),
159â†’                Pair(Pair("2012-06-30", "2012-07-01"), Pair(DateTimeUnit.YEAR, 0)),
160â†’                Pair(Pair("2012-06-30", "2012-07-07"), Pair(DateTimeUnit.DAY, 7)),
161â†’                Pair(Pair("2012-06-30", "2012-07-07"), Pair(DateTimeUnit.WEEK, 1)),
162â†’                Pair(Pair("2012-06-30", "2012-07-07"), Pair(DateTimeUnit.MONTH, 0)),
163â†’                Pair(Pair("2012-06-30", "2012-07-07"), Pair(DateTimeUnit.YEAR, 0)),
164â†’                Pair(Pair("2012-06-30", "2012-07-29"), Pair(DateTimeUnit.MONTH, 0)),
165â†’                Pair(Pair("2012-06-30", "2012-07-30"), Pair(DateTimeUnit.MONTH, 1)),
166â†’                Pair(Pair("2012-06-30", "2012-07-31"), Pair(DateTimeUnit.MONTH, 1)))
167â†’        for ((values, interval) in data) {
168â†’            val (v1, v2) = values
169â†’            val (unit, length) = interval
170â†’            val start = LocalDate.parse(v1)
171â†’            val end = LocalDate.parse(v2)
172â†’            assertEquals(length, start.until(end, unit), "$v2 - $v1 = $length($unit)")
173â†’            assertEquals(-length, end.until(start, unit), "$v1 - $v2 = -$length($unit)")
174â†’            when (unit) {
175â†’                DateTimeUnit.YEAR -> assertEquals(length, start.yearsUntil(end))
176â†’                DateTimeUnit.MONTH -> assertEquals(length, start.monthsUntil(end))
177â†’                DateTimeUnit.WEEK -> assertEquals(length, start.daysUntil(end) / 7)
178â†’                DateTimeUnit.DAY -> assertEquals(length, start.daysUntil(end))
179â†’                else -> error(unit)
180â†’            }
181â†’        }
182â†’
183â†’    }
