 52â†’/**
 53â†’ * A parser that accepts an [Int] value in range from `0` to [Int.MAX_VALUE].
 54â†’ */
 55â†’internal class UnsignedIntConsumer<in Receiver>(
 56â†’    private val minLength: Int?,
 57â†’    private val maxLength: Int?,
 58â†’    private val setter: AssignableField<Receiver, Int>,
 59â†’    name: String,
 60â†’    private val multiplyByMinus1: Boolean = false,
 61â†’) : NumberConsumer<Receiver>(if (minLength == maxLength) minLength else null, name) {
 62â†’
 63â†’    init {
 64â†’        require(length == null || length in 1..9) { "Invalid length for field $whatThisExpects: $length" }
 65â†’    }
 66â†’
 67â†’    override fun consume(storage: Receiver, input: CharSequence, start: Int, end: Int): NumberConsumptionError? = when {
 68â†’        maxLength != null && end - start > maxLength -> NumberConsumptionError.TooManyDigits(maxLength)
 69â†’        minLength != null && end - start < minLength -> NumberConsumptionError.TooFewDigits(minLength)
 70â†’        else -> when (val result = input.parseAsciiIntOrNull(start = start, end = end)) {
 71â†’            null -> NumberConsumptionError.ExpectedInt
 72â†’            else -> setter.setWithoutReassigning(storage, if (multiplyByMinus1) -result else result)
 73â†’        }
 74â†’    }
