154â†’private fun CharSequence.parseAsciiInt(start: Int, end: Int): Int {
155â†’    var result = 0
156â†’    for (i in start until end) {
157â†’        val digit = this[i]
158â†’        result = result * 10 + digit.asciiDigitToInt()
159â†’    }
160â†’    return result
