305â†’private val LocalDate.next: LocalDate get() =
306â†’    if (dayOfMonth != monthNumber.monthLength(isLeapYear(year))) {
307â†’        LocalDate(year, monthNumber, dayOfMonth + 1)
308â†’    } else if (monthNumber != 12) {
309â†’        LocalDate(year, monthNumber + 1, 1)
310â†’    } else {
311â†’        LocalDate(year + 1, 1, 1)
312â†’    }
313â†’
314â†’private val LocalDate.previous: LocalDate get() =
315â†’    if (dayOfMonth != 1) {
316â†’        LocalDate(year, monthNumber, dayOfMonth - 1)
317â†’    } else if (monthNumber != 1) {
318â†’        val newMonthNumber = monthNumber - 1
319â†’        LocalDate(year, newMonthNumber, newMonthNumber.monthLength(isLeapYear(year)))
320â†’    } else {
321â†’        LocalDate(year - 1, 12, 31)
322â†’    }
